// Convert the downloaded PDF binary to base64 for Claude API
const binaryData = $input.item.binary.data;
const base64Content = binaryData.data;
const fileName = binaryData.fileName || 'document.pdf';
const mimeType = binaryData.mimeType || 'application/pdf';

return {
  json: {
    ...$input.item.json,
    base64_pdf: base64Content,
    file_name: fileName,
    mime_type: mimeType
  }
};

