// Parse Claude's JSON response
const response = $input.item.json;
let content = '';

// Extract text from Claude's response format
if (response.content && Array.isArray(response.content)) {
  content = response.content.map(c => c.text || '').join('');
} else if (typeof response === 'string') {
  content = response;
}

// Clean up: remove markdown code fences if present
content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

// Parse the JSON
let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  // Try to extract JSON from the text
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    parsed = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('Could not parse Claude response as JSON: ' + content.substring(0, 200));
  }
}

return {
  json: {
    ...$input.item.json,
    parsed_response: parsed,
    source_title: parsed.source_title || 'Unknown',
    source_date: parsed.source_date || new Date().toISOString().split('T')[0],
    summary: parsed.summary || '',
    action_items: parsed.action_items || [],
    item_count: (parsed.action_items || []).length
  }
};

// Build Obsidian-compatible Markdown from parsed response
const item = $input.item.json;
const parsed = item.parsed_response;

let md = `# ${parsed.source_title || 'Untitled'}\n\n`;
md += `**Date:** ${parsed.source_date || 'Unknown'}\n`;
md += `**Summary:** ${parsed.summary || 'No summary'}\n\n`;
md += `---\n\n`;
md += `## Action Items\n\n`;

const actions = parsed.action_items || [];
for (const a of actions) {
  const priority = a.priority === 'High' ? '🔴' : a.priority === 'Medium' ? '🟡' : '🟢';
  md += `### ${priority} ${a.action_description}\n`;
  md += `- **Type:** ${a.item_type}\n`;
  md += `- **Domain:** ${a.domain}\n`;
  md += `- **PARA:** ${a.para_category}\n`;
  if (a.project) md += `- **Project:** ${a.project}\n`;
  if (a.context) md += `- **Context:** ${a.context}\n`;
  if (a.due_date) md += `- **Due:** ${a.due_date}\n`;
  md += `\n`;
}

return {
  json: {
    ...item,
    obsidian_markdown: md,
    file_name_md: (parsed.source_title || 'note').replace(/[^a-zA-Z0-9\s-]/g, '').replace(/\s+/g, '_') + '.md'
  }
};

// Split action_items array into individual items for Notion processing
const item = $input.item.json;
const actions = item.action_items || [];
const sourceTitle = item.source_title || 'Unknown';
const sourceDate = item.source_date || new Date().toISOString().split('T')[0];
const fileName = item.file_name || 'unknown.pdf';

const results = actions.map(a => ({
  json: {
    action_description: a.action_description || '',
    priority: a.priority || 'Medium',
    item_type: a.item_type || 'Action',
    domain: a.domain || 'Personal',
    para_category: a.para_category || 'Area',
    project: a.project || '',
    context: a.context || '',
    due_date: a.due_date || null,
    event_time: a.event_time || null,
    source_title: sourceTitle,
    source_date: sourceDate,
    source_file: fileName
  }
}));

return results;

// Build the Notion API request body for each action item
const item = $json;

// === EMOJI MAPPINGS ===
const priorityMap = { 'High': '🔴 High', 'Medium': '🟡 Medium', 'Low': '🟢 Low' };
const typeMap = { 'Action': '✅ Action', 'Project': '📋 Project', 'Event': '📅 Event', 'Reference': '📚 Reference', 'Idea': '💡 Idea' };
const paraMap = { 'Project': '📁 Project', 'Area': '🏠 Area', 'Resource': '📚 Resource', 'Archive': '🗄️ Archive' };
const domainMap = { 'Work': '🏢 Work', 'Personal': '🏠 Personal', 'Health': '💪 Health', 'Finance': '💰 Finance', 'Learning': '📖 Learning' };

// === BUILD PROPERTIES ===
const properties = {};

// Title
properties['Action Item'] = { title: [{ text: { content: item.action_description || 'Untitled' } }] };

// Select properties
properties['Priority'] = { select: { name: priorityMap[item.priority] || '🟡 Medium' } };
properties['Type'] = { select: { name: typeMap[item.item_type] || '✅ Action' } };
properties['Domain'] = { select: { name: domainMap[item.domain] || '🏠 Personal' } };
properties['PARA Category'] = { select: { name: paraMap[item.para_category] || '🏠 Area' } };
properties['Status'] = { select: { name: '📥 Inbox' } };
properties['Review Status'] = { select: { name: 'Pending Review' } };

// Text properties
if (item.context) {
  properties['Context'] = { rich_text: [{ text: { content: item.context } }] };
}
if (item.project) {
  properties['Project'] = { rich_text: [{ text: { content: item.project } }] };
}
if (item.source_file) {
  properties['Source PDF'] = { rich_text: [{ text: { content: item.source_file } }] };
}

// Date properties
properties['Captured'] = { date: { start: new Date().toISOString().split('T')[0] } };
if (item.due_date) {
  properties['Due Date'] = { date: { start: item.due_date } };
}
if (item.event_time) {
  properties['Event Time'] = { rich_text: [{ text: { content: item.event_time } }] };
}

// === ASSEMBLE FULL BODY ===
const body = {
  parent: { database_id: "YOUR_NOTION_DATABASE_ID" },
  properties: properties,
  children: [
    {
      object: "block",
      type: "heading_2",
      heading_2: { rich_text: [{ type: "text", text: { content: "Context" } }] }
    },
    {
      object: "block",
      type: "paragraph",
      paragraph: { rich_text: [{ type: "text", text: { content: item.context || "No additional context" } }] }
    },
    {
      object: "block",
      type: "heading_2",
      heading_2: { rich_text: [{ type: "text", text: { content: "Source Details" } }] }
    },
    {
      object: "block",
      type: "paragraph",
      paragraph: { rich_text: [{ type: "text", text: { content: "Priority: " + (item.priority || "N/A") + " | Type: " + (item.item_type || "N/A") + " | Domain: " + (item.domain || "N/A") } }] }
    },
    {
      object: "block",
      type: "paragraph",
      paragraph: { rich_text: [{ type: "text", text: { content: "Project: " + (item.project || "N/A") + " | PARA: " + (item.para_category || "N/A") } }] }
    },
    ...(item.due_date ? [{
      object: "block",
      type: "paragraph",
      paragraph: { rich_text: [{ type: "text", text: { content: "Due: " + item.due_date + (item.event_time ? " at " + item.event_time : "") } }] }
    }] : [])
  ]
};

return { json: { ...item, _notion_body: body } };

